import { useState } from 'react';import { useMutation,useQueryClient } from '@tanstack/react-query';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { apiErrorMessage } from '@/lib/apiClient';import { vendorApi } from '../api/vendorApi';import type { SupplierCategory } from '../types';
export const CategoryManager=({categories}:{categories:SupplierCategory[]})=>{const [editing,setEditing]=useState<SupplierCategory|null>(null);const [form,setForm]=useState({code:'',name:'',description:'',status:'active' as 'active'|'inactive'});const client=useQueryClient();const save=useMutation({mutationFn:()=>editing?vendorApi.updateCategory(editing.id,form):vendorApi.createCategory(form),onSuccess:()=>{setEditing(null);setForm({code:'',name:'',description:'',status:'active'});void client.invalidateQueries({queryKey:['vendors','categories']});}});const remove=useMutation({mutationFn:vendorApi.deleteCategory,onSuccess:()=>void client.invalidateQueries({queryKey:['vendors','categories']})});const open=(x:SupplierCategory)=>{setEditing(x);setForm({code:x.code,name:x.name,description:x.description??'',status:x.status});};const cls='h-10 rounded-lg border border-slate-300 bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800';return <div className="space-y-5">{save.error||remove.error?<Alert variant="danger" title="Category operation failed">{apiErrorMessage(save.error||remove.error)}</Alert>:null}<div className="grid gap-3 sm:grid-cols-2"><input aria-label="Category code" placeholder="Code" value={form.code} onChange={e=>setForm({...form,code:e.target.value.toUpperCase()})} className={cls}/><input aria-label="Category name" placeholder="Category name" value={form.name} onChange={e=>setForm({...form,name:e.target.value})} className={cls}/><input aria-label="Category description" placeholder="Description" value={form.description} onChange={e=>setForm({...form,description:e.target.value})} className={`${cls} sm:col-span-2`}/><select aria-label="Category status" value={form.status} onChange={e=>setForm({...form,status:e.target.value as 'active'|'inactive'})} className={cls}><option value="active">Active</option><option value="inactive">Inactive</option></select><div className="flex gap-2"><Button disabled={!form.code.trim()||!form.name.trim()} isLoading={save.isPending} onClick={()=>save.mutate()}>{editing?'Save Category':'Add Category'}</Button>{editing?<Button variant="secondary" onClick={()=>{setEditing(null);setForm({code:'',name:'',description:'',status:'active'});}}>Cancel</Button>:null}</div></div><div className="divide-y rounded-xl border dark:divide-slate-700 dark:border-slate-700">{categories.map(x=><div key={x.id} className="flex items-center justify-between p-3"><div><p className="font-semibold">{x.name} <span className="font-mono text-xs text-indigo-600">{x.code}</span></p><p className="text-xs text-slate-500">{x.supplier_count??0} suppliers · {x.status}</p></div><div className="flex gap-2"><button className="text-xs font-semibold text-indigo-600" onClick={()=>open(x)}>Edit</button><button className="text-xs font-semibold text-red-600" onClick={()=>{if(confirm(`Archive category ${x.name}?`))remove.mutate(x.id);}}>Archive</button></div></div>)}</div></div>;};
